13:   if (!match || !match[1] || !match[2] || !match[3]) throw new Error("Invalid format");
14: 
15:   const valueStr = match[1];
16:   const typePrefix = match[2]; // "U" or "I"
17:   const bits = parseInt(match[3], 10);
18: 
19:   let minValue: bigint;
20:   let maxValue: bigint;
21: 
22:   if (typePrefix === "U") {
23:     minValue = 0n;
24:     maxValue = (1n << BigInt(bits)) - 1n;
25:   } else {
26:     const signBitShift = BigInt(bits) - 1n;
27:     minValue = -(1n << signBitShift);
28:     maxValue = (1n << signBitShift) - 1n;
29:   }
30: 
