32: 
33:   if (typePrefix === "U") {
34:     if (value < minValue) throw new Error("Negative values are not supported");
35:     if (value > maxValue) throw new Error(`Value exceeds maximum for ${typePrefix}${bits}`);
36:   } else {
37:     if (value < minValue || value > maxValue)
38:       throw new Error(`Value out of range for ${typePrefix}${bits}`);
39:   }
40: 
41:   if (value <= Number.MAX_SAFE_INTEGER && bits !== 64) return Number(value);
42:   return value;
43: }
