514: export function executeTuff(tuffSourceCode: string): number | bigint {
515:   if (tuffSourceCode === "") return 0;
516: 
517:   const tokens = tokenize(tuffSourceCode);
518:   let pos = 0;
519:   const scope = new Map<
520:     string,
521:     { value: bigint; type: string; mutable: boolean }
522:   >();
523: 
524:   const ctx: ParserCtx = {
525:     tokens,
526:     get pos() { return pos; },
527:     set pos(v) { pos = v; },
528:     scope,
529:   };
