531:   let finalResult = 0n;
532:   while (pos < tokens.length) {
533:     const itemValue = parseBlockItem(ctx);
534:     if (itemValue !== null) finalResult = BigInt(itemValue);
535:   }
536: 
537:   return normalizeResult(finalResult);
538: }

